CREATE SEQUENCE seq_orders START WITH 1 INCREMENT BY 1;
CREATE SEQUENCE IF NOT EXISTS seq_invoices START WITH 1000 MAXVALUE 99999 CYCLE;
CREATE OR REPLACE SEQUENCE seq_users START WITH 1 INCREMENT BY 1 NOCACHE;
DROP SEQUENCE seq_orders;
DROP SEQUENCE IF EXISTS seq_invoices;
ALTER SEQUENCE seq_orders RESTART WITH 1;
